const niche = $.input.niche;
const query = 'trending viral short-form video ideas for ' + niche + ' 2024 2025';
return { query };

const results = $.steps.searchTrends.response.results || [];
let compiled = '';
results.forEach((r, i) => {
  compiled += (i + 1) + '. ' + (r.title || 'Untitled') + '\n';
  compiled += '   URL: ' + (r.url || '') + '\n';
  compiled += '   ' + (r.text || '').slice(0, 1000) + '\n\n';
});
return { compiled, sourceCount: results.length };

const d = $.steps.compileTrends.output;
const niche = $.input.niche;
const count = $.input.numberOfScripts || 5;
const platform = $.input.targetPlatform || 'YouTube Shorts';

let prompt = 'You are an expert short-form video content strategist. Create ' + count + ' high-performing video scripts for ' + platform + '.\n\n';
prompt += 'NICHE: ' + niche + '\n';
prompt += 'TARGET PLATFORM: ' + platform + '\n';
prompt += 'SCRIPTS NEEDED: ' + count + '\n\n';
prompt += 'TRENDING RESEARCH (' + d.sourceCount + ' sources):\n';
prompt += d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Each script should be 30-60 seconds when spoken\n';
prompt += '- Include a strong hook in the first 3 seconds\n';
prompt += '- Include visual direction notes\n';
prompt += '- End with a clear CTA\n';
prompt += '- Optimize for engagement (saves, shares, comments)\n';
prompt += '- Vary the content angles across scripts\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "scripts": [\n';
prompt += '    {\n';
prompt += '      "title": "video title",\n';
prompt += '      "hook": "attention-grabbing first 3 seconds",\n';
prompt += '      "script": "full narration script",\n';
prompt += '      "visualNotes": "what to show on screen",\n';
prompt += '      "cta": "call to action",\n';
prompt += '      "hashtags": ["tag1", "tag2"],\n';
prompt += '      "estimatedDuration": "30s|45s|60s",\n';
prompt += '      "viralPotential": "high|medium|low",\n';
prompt += '      "contentAngle": "educational|entertaining|inspiring|controversial"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "contentStrategy": "overall strategy note for the batch",\n';
prompt += '  "postingSchedule": "recommended posting frequency and times"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { scripts: [], contentStrategy: raw, postingSchedule: '' }; }

const ai = $.steps.parseAI.output;
const today = new Date().toISOString().slice(0, 10);
const rows = [];
rows.push(['Date', 'Title', 'Hook', 'Script', 'Visual Notes', 'CTA', 'Hashtags', 'Duration', 'Viral Potential', 'Angle']);
(ai.scripts || []).forEach(s => {
  rows.push([today, s.title || '', s.hook || '', s.script || '', s.visualNotes || '', s.cta || '', (s.hashtags || []).join(', '), s.estimatedDuration || '', s.viralPotential || '', s.contentAngle || '']);
});
return { rows };

const ai = $.steps.parseAI.output;
const scripts = ai.scripts || [];
const platform = $.input.targetPlatform || 'YouTube Shorts';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: platform + ' Content Plan', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Niche:* ' + $.input.niche + ' | *Scripts Generated:* ' + scripts.length } });
if (ai.contentStrategy) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Strategy:* ' + ai.contentStrategy.slice(0, 500) } });
}
blocks.push({ type: 'divider' });

scripts.slice(0, 5).forEach((s, i) => {
  const viralIcon = s.viralPotential === 'high' ? ':fire:' : s.viralPotential === 'medium' ? ':chart_with_upwards_trend:' : ':seedling:';
  let text = viralIcon + ' *' + (i + 1) + '. ' + (s.title || 'Untitled') + '* (' + (s.estimatedDuration || '?') + ')\n';
  text += '_Hook:_ ' + (s.hook || '') + '\n';
  text += '_Angle:_ ' + (s.contentAngle || '') + ' | _CTA:_ ' + (s.cta || '') + '\n';
  if (s.hashtags && s.hashtags.length > 0) text += s.hashtags.map(h => '#' + h).join(' ') + '\n';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 1800) } });
});

if (ai.postingSchedule) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Posting Schedule:* ' + ai.postingSchedule } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Scripts saved to Google Sheets | Powered by Exa + Claude AI' }] });
const fallback = platform + ' Plan: ' + scripts.length + ' scripts for ' + $.input.niche;
return { blocks, fallback };
